// Helper function to generate card image URLs from Cloudinary
export function getCardImageUrl(card) {
  if (!card || !card.character) return null;
  const characterSlug = card.character.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  const raritySlug = (card.rarity || 'core').toLowerCase().replace(/\s+/g, '');

  // Cloudinary URL format
  const cloudName = process.env.REACT_APP_CLOUDINARY_CLOUD_NAME || 'dfecvzwvg';
  return `https://res.cloudinary.com/${cloudName}/image/upload/veefriends/cards/${characterSlug}-${raritySlug}.png`;
}

// Fallback for when image fails to load
export function getCardFallbackImage(card) {
  const cloudName = process.env.REACT_APP_CLOUDINARY_CLOUD_NAME || 'dfecvzwvg';
  if (!card || !card.character) {
    return `https://res.cloudinary.com/${cloudName}/image/upload/veefriends/cards/card-back.png`;
  }

  // Try the image field from metadata as fallback
  if (card.image) {
    return `https://res.cloudinary.com/${cloudName}/image/upload/veefriends/cards/${card.image}`;
  }
  return `https://res.cloudinary.com/${cloudName}/image/upload/veefriends/cards/default-card.png`;
}

